const { ethers } = require('ethers');

const ERC20_ABI = [
  'function balanceOf(address owner) view returns (uint256)',
  'function allowance(address owner, address spender) view returns (uint256)',
  'function approve(address spender, uint256 amount) returns (bool)',
  'function decimals() view returns (uint8)',
  'function symbol() view returns (string)',
  'function name() view returns (string)'
];

const DEX_ABI = [
  'function swapExactTokensForTokens(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) returns (uint256[] memory amounts)',
  'function swapTokensForExactTokens(uint256 amountOut, uint256 amountInMax, address[] calldata path, address to, uint256 deadline) returns (uint256[] memory amounts)',
  'function getAmountsOut(uint256 amountIn, address[] calldata path) view returns (uint256[] memory amounts)',
  'function getAmountsIn(uint256 amountOut, address[] calldata path) view returns (uint256[] memory amounts)',
  'function factory() view returns (address)',
  'function WETH() view returns (address)'
];

const FACTORY_ABI = [
  'function getPair(address tokenA, address tokenB) view returns (address pair)'
];

const PAIR_ABI = [
  'function getReserves() view returns (uint112 reserve0, uint112 reserve1, uint32 blockTimestampLast)',
  'function token0() view returns (address)',
  'function token1() view returns (address)'
];

class TokenSwapDApp {
  constructor(dexAddress, provider) {
    this.dexAddress = dexAddress;
    this.provider = provider;
    this.signer = null;
    this.dexContract = null;
    this.factoryAddress = null;
    this.MAX_UINT256 = ethers.MaxUint256;
  }

  async initialize() {
    this.signer = await this.provider.getSigner();
    this.dexContract = new ethers.Contract(this.dexAddress, DEX_ABI, this.signer);
    this.factoryAddress = await this.dexContract.factory();
  }

  async getTokenContract(tokenAddress) {
    return new ethers.Contract(tokenAddress, ERC20_ABI, this.signer);
  }

  async getTokenInfo(tokenAddress) {
    const tokenContract = await this.getTokenContract(tokenAddress);
    const [name, symbol, decimals] = await Promise.all([
      tokenContract.name(),
      tokenContract.symbol(),
      tokenContract.decimals()
    ]);
    return { name, symbol, decimals, address: tokenAddress };
  }

  async getTokenBalance(tokenAddress, userAddress) {
    const tokenContract = await this.getTokenContract(tokenAddress);
    const balance = await tokenContract.balanceOf(userAddress);
    return balance;
  }

  async checkAllowance(tokenAddress, userAddress, spenderAddress) {
    const tokenContract = await this.getTokenContract(tokenAddress);
    const allowance = await tokenContract.allowance(userAddress, spenderAddress);
    return allowance;
  }

  async approveToken(tokenAddress, spenderAddress, amount = null) {
    const tokenContract = await this.getTokenContract(tokenAddress);
    const approvalAmount = amount || this.MAX_UINT256;
    
    const tx = await tokenContract.approve(spenderAddress, approvalAmount);
    const receipt = await tx.wait();
    
    return {
      transactionHash: receipt.hash,
      success: receipt.status === 1,
      gasUsed: receipt.gasUsed
    };
  }

  async approveMaxAmount(tokenAddress) {
    return await this.approveToken(tokenAddress, this.dexAddress, this.MAX_UINT256);
  }

  async ensureApproval(tokenAddress, userAddress, requiredAmount) {
    const currentAllowance = await this.checkAllowance(tokenAddress, userAddress, this.dexAddress);
    
    if (currentAllowance < requiredAmount) {
      return await this.approveMaxAmount(tokenAddress);
    }
    
    return { alreadyApproved: true };
  }

  async getQuote(amountIn, tokenIn, tokenOut) {
    const path = [tokenIn, tokenOut];
    try {
      const amounts = await this.dexContract.getAmountsOut(amountIn, path);
      return amounts[amounts.length - 1];
    } catch (error) {
      throw new Error(`Failed to get quote: ${error.message}`);
    }
  }

  async getAmountIn(amountOut, tokenIn, tokenOut) {
    const path = [tokenIn, tokenOut];
    try {
      const amounts = await this.dexContract.getAmountsIn(amountOut, path);
      return amounts[0];
    } catch (error) {
      throw new Error(`Failed to get amount in: ${error.message}`);
    }
  }

  async getPairReserves(tokenA, tokenB) {
    const factoryContract = new ethers.Contract(this.factoryAddress, FACTORY_ABI, this.provider);
    const pairAddress = await factoryContract.getPair(tokenA, tokenB);
    
    if (pairAddress === ethers.ZeroAddress) {
      throw new Error('Pair does not exist');
    }
    
    const pairContract = new ethers.Contract(pairAddress, PAIR_ABI, this.provider);
    const [reserve0, reserve1] = await pairContract.getReserves();
    const token0 = await pairContract.token0();
    const token1 = await pairContract.token1();
    
    return {
      pairAddress,
      reserve0,
      reserve1,
      token0,
      token1
    };
  }

  calculatePriceImpact(amountIn, amountOut, reserveIn, reserveOut) {
    const expectedPrice = (reserveOut * amountIn) / reserveIn;
    const actualPrice = amountOut;
    const priceImpact = ((expectedPrice - actualPrice) / expectedPrice) * 100n;
    return priceImpact;
  }

  async swapExactTokensForTokens(tokenIn, tokenOut, amountIn, slippageTolerance = 0.5) {
    const userAddress = await this.signer.getAddress();
    
    await this.ensureApproval(tokenIn, userAddress, amountIn);
    
    const amountOut = await this.getQuote(amountIn, tokenIn, tokenOut);
    const slippageMultiplier = (100 - slippageTolerance) / 100;
    const amountOutMin = (amountOut * BigInt(Math.floor(slippageMultiplier * 1000))) / 1000n;
    
    const path = [tokenIn, tokenOut];
    const deadline = Math.floor(Date.now() / 1000) + 60 * 20;
    
    const tx = await this.dexContract.swapExactTokensForTokens(
      amountIn,
      amountOutMin,
      path,
      userAddress,
      deadline
    );
    
    const receipt = await tx.wait();
    
    return {
      transactionHash: receipt.hash,
      success: receipt.status === 1,
      gasUsed: receipt.gasUsed,
      amountIn,
      expectedAmountOut: amountOut,
      minimumAmountOut: amountOutMin
    };
  }

  async swapTokensForExactTokens(tokenIn, tokenOut, amountOut, slippageTolerance = 0.5) {
    const userAddress = await this.signer.getAddress();
    
    const amountIn = await this.getAmountIn(amountOut, tokenIn, tokenOut);
    const slippageMultiplier = (100 + slippageTolerance) / 100;
    const amountInMax = (amountIn * BigInt(Math.floor(slippageMultiplier * 1000))) / 1000n;
    
    await this.ensureApproval(tokenIn, userAddress, amountInMax);
    
    const path = [tokenIn, tokenOut];
    const deadline = Math.floor(Date.now() / 1000) + 60 * 20;
    
    const tx = await this.dexContract.swapTokensForExactTokens(
      amountOut,
      amountInMax,
      path,
      userAddress,
      deadline
    );
    
    const receipt = await tx.wait();
    
    return {
      transactionHash: receipt.hash,
      success: receipt.status === 1,
      gasUsed: receipt.gasUsed,
      expectedAmountIn: amountIn,
      maximumAmountIn: amountInMax,
      amountOut
    };
  }

  async getSwapDetails(tokenIn, tokenOut, amountIn) {
    const [tokenInInfo, tokenOutInfo] = await Promise.all([
      this.getTokenInfo(tokenIn),
      this.getTokenInfo(tokenOut)
    ]);
    
    const amountOut = await this.getQuote(amountIn, tokenIn, tokenOut);
    
    const reserves = await this.getPairReserves(tokenIn, tokenOut);
    
    let reserveIn, reserveOut;
    if (reserves.token0.toLowerCase() === tokenIn.toLowerCase()) {
      reserveIn = reserves.reserve0;
      reserveOut = reserves.reserve1;
    } else {
      reserveIn = reserves.reserve1;
      reserveOut = reserves.reserve0;
    }
    
    const priceImpact = this.calculatePriceImpact(amountIn, amountOut, reserveIn, reserveOut);
    
    const price = (amountOut * (10n ** BigInt(tokenInInfo.decimals))) / amountIn;
    const inversePrice = (amountIn * (10n ** BigInt(tokenOutInfo.decimals))) / amountOut;
    
    return {
      tokenIn: tokenInInfo,
      tokenOut: tokenOutInfo,
      amountIn,
      amountOut,
      price,
      inversePrice,
      priceImpact,
      reserves: {
        pairAddress: reserves.pairAddress,
        reserveIn,
        reserveOut
      }
    };
  }

  async executeSwap(params) {
    const { tokenIn, tokenOut, amountIn, amountOut, isExactIn, slippageTolerance } = params;
    
    if (isExactIn) {
      return await this.swapExactTokensForTokens(tokenIn, tokenOut, amountIn, slippageTolerance);
    } else {
      return await this.swapTokensForExactTokens(tokenIn, tokenOut, amountOut, slippageTolerance);
    }
  }

  async batchApproveTokens(tokenAddresses) {
    const results = [];
    for (const tokenAddress of tokenAddresses) {
      try {
        const result = await this.approveMaxAmount(tokenAddress);
        results.push({ tokenAddress, ...result });
      } catch (error) {
        results.push({ tokenAddress, error: error.message });
      }
    }
    return results;
  }

  async getUserBalances(userAddress, tokenAddresses) {
    const balances = {};
    for (const tokenAddress of tokenAddresses) {
      const balance = await this.getTokenBalance(tokenAddress, userAddress);
      const tokenInfo = await this.getTokenInfo(tokenAddress);
      balances[tokenAddress] = {
        balance,
        ...tokenInfo
      };
    }
    return balances;
  }

  async getAllowances(userAddress, tokenAddresses) {
    const allowances = {};
    for (const tokenAddress of tokenAddresses) {
      const allowance = await this.checkAllowance(tokenAddress, userAddress, this.dexAddress);
      allowances[tokenAddress] = allowance;
    }
    return allowances;
  }

  formatAmount(amount, decimals) {
    return ethers.formatUnits(amount, decimals);
  }

  parseAmount(amount, decimals) {
    return ethers.parseUnits(amount, decimals);
  }
}

class SwapUI {
  constructor(dapp) {
    this.dapp = dapp;
  }

  async initializeSwapForm(tokenInAddress, tokenOutAddress) {
    const userAddress = await this.dapp.signer.getAddress();
    
    const [balances, allowances, tokenInInfo, tokenOutInfo] = await Promise.all([
      this.dapp.getUserBalances(userAddress, [tokenInAddress, tokenOutAddress]),
      this.dapp.getAllowances(userAddress, [tokenInAddress, tokenOutAddress]),
      this.dapp.getTokenInfo(tokenInAddress),
      this.dapp.getTokenInfo(tokenOutAddress)
    ]);
    
    return {
      userAddress,
      tokenIn: {
        ...tokenInInfo,
        balance: balances[tokenInAddress].balance,
        allowance: allowances[tokenInAddress],
        needsApproval: allowances[tokenInAddress] === 0n
      },
      tokenOut: {
        ...tokenOutInfo,
        balance: balances[tokenOutAddress].balance,
        allowance: allowances[tokenOutAddress]
      }
    };
  }

  async updateQuote(tokenInAddress, tokenOutAddress, amountIn) {
    const swapDetails = await this.dapp.getSwapDetails(tokenInAddress, tokenOutAddress, amountIn);
    
    return {
      amountIn: this.dapp.formatAmount(swapDetails.amountIn, swapDetails.tokenIn.decimals),
      amountOut: this.dapp.formatAmount(swapDetails.amountOut, swapDetails.tokenOut.decimals),
      price: this.dapp.formatAmount(swapDetails.price, swapDetails.tokenOut.decimals),
      priceImpact: Number(swapDetails.priceImpact) / 100,
      route: [swapDetails.tokenIn.symbol, swapDetails.tokenOut.symbol]
    };
  }

  async handleApproval(tokenAddress) {
    const result = await this.dapp.approveMaxAmount(tokenAddress);
    return result;
  }

  async handleSwap(tokenInAddress, tokenOutAddress, amountInString, slippageTolerance = 0.5) {
    const tokenInInfo = await this.dapp.getTokenInfo(tokenInAddress);
    const amountIn = this.dapp.parseAmount(amountInString, tokenInInfo.decimals);
    
    const result = await this.dapp.executeSwap({
      tokenIn: tokenInAddress,
      tokenOut: tokenOutAddress,
      amountIn,
      isExactIn: true,
      slippageTolerance
    });
    
    return result;
  }
}

async function createDApp(dexAddress, providerUrl) {
  let provider;
  if (typeof window !== 'undefined' && window.ethereum) {
    provider = new ethers.BrowserProvider(window.ethereum);
    await provider.send('eth_requestAccounts', []);
  } else {
    provider = new ethers.JsonRpcProvider(providerUrl);
  }
  
  const dapp = new TokenSwapDApp(dexAddress, provider);
  await dapp.initialize();
  
  return dapp;
}

module.exports = {
  TokenSwapDApp,
  SwapUI,
  createDApp
};